import java.util.Arrays;

public class DynamicArrayList {
    private String[] elements;
    private int size;

    public DynamicArrayList() {
        elements = new String[4]; // Initial capacity
        size = 0;
    }

    public void add(String element) {
        if (size == elements.length) {
            resize();
        }
        elements[size++] = element;
    }

    private void resize() {
        elements = Arrays.copyOf(elements, elements.length * 2);
    }

    public String get(int index) {
        if (index < 0 || index >= size) {
            throw new IndexOutOfBoundsException();
        }
        return elements[index];
    }

    public int size() {
        return size;
    }

    public static void main(String[] args) {
        DynamicArrayList list = new DynamicArrayList();
        list.add("Hello");
        list.add("World");
        System.out.println(list.get(0)); // Output: Hello
        System.out.println(list.get(1)); // Output: World
        System.out.println("Size: " + list.size()); // Output: Size: 2
