```java
import java.util.Arrays;

public class DynamicArrayList {
    private String[] attendees;
    private int size;

    public DynamicArrayList() {
        attendees = new String[4]; // Initial capacity
        size = 0;
    }

    public void register(String attendee) {
        if (size == attendees.length) {
            resize();
        }
        attendees[size++] = attendee;
    }

    public void withdraw(int index) {
        if (index < 0 || index >= size) {
            throw new IndexOutOfBoundsException();
        }
        // Shift elements left to fill the gap
        for (int i = index; i < size - 1; i++) {
            attendees[i] = attendees[i + 1];
        }
        attendees[--size] = null; // Avoid loitering
    }

    private void resize() {
        attendees = Arrays.copyOf(attendees, attendees.length * 2);
    }

    public String getAttendee(int index) {
        if (index < 0 || index >= size) {
            throw new IndexOutOfBoundsException();
        }
        return attendees[index];
    }

    public int size() {
        return size;
    }

    public static void main(String[] args) {
        DynamicArrayList event = new DynamicArrayList();
        event.register("Alice");
        event.register("Bob");
        System.out.println(event.getAttendee(0)); // Output: Alice
        System.out.println(event.getAttendee(1)); // Output: Bob
        event.withdraw(0); // Alice withdraws
        System.out.println("Size: " + event.size()); // Output: Size: 1
    }
}
```

